            mid1 = (low + high) // 2
            mid2 = left - mid1

            left1 = -sys.maxsize
            left2 = -sys.maxsize
            right1 = sys.maxsize
            right2 = sys.maxsize

            if mid1 < size1:
                right1 = nums1[mid1]
            if mid2 < size2:
                right2 = nums2[mid2]
            if mid1 - 1 >= 0:
                left1 = nums1[mid1 - 1]
            if mid2 - 1 >= 0:
                left2 = nums2[mid2 - 1]

            if left1 <= right2 and left2 <= right1:
                if summ % 2 == 0:
                    return (max(left1, left2) + min(right1, right2)) / 2
                else:
