class Solution {
public:

    string intToRoman(int num) {

        const vector<pair<int, string>> roman_symbols{
            {M, "M"}, {M - C, "CM"}, {D, "D"}, {D - C, "CD"}, {C, "C"},
            {C - X, "XC"},  {L , "L"},   {L - X, "XL"}, {X, "X"},   {X - I, "IX"},
            {V, "V"},    {V - I, "IV"},   {I, "I"}
            };

        string myString;

        for(const auto& [value, symbol] : roman_symbols){
            if (num == 0)
                break;

            while(num>= value){
                myString += symbol;
                num -= value;
            }

        }

        return myString;
    }
};

class Solution {
public:
    int romanToInt(string s) {
        int n = s.size();
        unordered_map<char, int> myHashMap = {
            {'I', 1}, 
            {'V', 5}, 
            {'X', 10}, 
            {'L', 50}, 
            {'C', 100}, 
            {'D', 500}, 
            {'M', 1000}
        };

        int total = 0;
        int max_num = myHashMap[s[n-1]];
        for(int c = n-1; c >= 0; c--){
            int temp = myHashMap[s[c]];
            if(max_num <= temp){
                total += temp;
            } else{
                total -= temp;
            }
            max_num = (max_num, temp);
        }

        return total;



    }
};

