class Solution {
public:
    string longestCommonPrefix(vector<string>& strs) {
        int n = strs.size();
        if (n == 0)
            return "";

        int str_len = strs[0].size();

        int length = 0;

        for(int x = 0; x < str_len; x++){

            char pre = strs[0][x];
            for(int i = 0; i < n; i++){
                if(strs[i].size() < x || strs[i][x] != pre)
                    return strs[0].substr(0, length);

            }
            length++;
        }
        return strs[0].substr(0, length);

    }
};

class Solution {
    public:
        vector<vector<int>> threeSum(vector<int>& nums) {    
             vector<vector<int>> result;

             unordered_map<int, int> map;

             for(int key: nums){
                auto it = map.find(key);
                if (it == map.end()) {
                    map[key] = 1;
                } else{
                    map[key]++;
                }
             }

             int l = 0, r = nums.size()-1;

             int min = nums[0];

             while(l < r){
                int target = -(nums[l] + nums[r]);

                auto it = map.find(target);
                if(it != map.end()){
                    if((nums[l] != target && nums[r] != target) || it->second >= 2){
                        int left = nums[l], right = nums[r];
                        if(left > right){
                            swap(left, right);
                        }

                        if(target > right)
                            result.push_back({left, right, target});
                        else if(target < left)
                            result.push_back({target, left, right});
                        else
                            result.push_back({left, target,  right});
                    }
                    l++;
                    continue;
                }

                if (nums[l] + nums[r] > -min) {
                    l++;
                } else {
                    r--;
                }
             }

            sort(result.begin(), result.end());

            auto last = unique(result.begin(), result.end());

            result.erase(last, result.end());


             return result;

        }
    };

