                    adddigit(solution, temp, "mno");
                    break;
                case '7': 
                    adddigit(solution, temp, "pqrs");
                    break;
                case '8': 
                    adddigit(solution, temp, "tuv");
                    break;
                case '9': 
                    adddigit(solution, temp, "wxyz");
                    break;
            }
            solution = temp;
        }
