    void adddigit(const vector<string>& solution, vector<string>& temp, const string& letters) {
        for(auto character : letters) {
            for(auto i : solution) {
                temp.push_back(i + character);
            }
        }
    }
};

class Solution:
    def isValid(self, s: str) -> bool:
        stack = deque()
        negate = {')':'(', '}':'{', ']':'['}

        for ch in s:
            if ord(ch) % 4 == 1:
                if not stack or stack.pop() != negate[ch]:
                    return False
            else:
                stack.append(ch)

        return not bool(stack)

class Solution:
    def mergeTwoLists(self, list1: Optional[ListNode], list2: Optional[ListNode]) -> Optional[ListNode]:
        if list1 is None and list2 is None:
            return None

        result = ListNode()
        head = result
        while list1 is not None and list2 is not None:

            if list1.val > list2.val:
                temp = list2
                list2 = list2.next
            else:
                temp = list1
                list1 = list1.next

            result.next = temp
            result = result.next

        if list1 is None:
            result.next = list2
        else:
            result.next = list1


        return head.next

class Solution:
    def generateParenthesis(self, n: int) -> List[str]:
        result: List[str] = []

        def dfs(number: int, item: str, fill: int):
            if number == 0:
                result.append(item + ")" * fill)
                return
            if fill > 0:
                dfs(number, item + ")", fill - 1)
            dfs(number - 1, item + "(", fill + 1)


        dfs(n , "", 0)
        return result

