    int jump(vector<int>& nums) {
        int n = nums.size();
        int jumps = 0;

        int i = 0;
        while(i < n){
            int index = nums[i] + i;
            int highest = index;
            int high_index = i;
            for(int x = i; x < n && x <= index; x++){
                int temp = nums[x] + x;

                if (temp >= highest && nums[x] != 0){
                    highest = temp;
                    high_index = x;
                }
            }
            jumps++;

            if(nums[high_index] + high_index > n-2){
                return jumps+1;
            }
            if (highest == index)
                return -1;
            else{
                i = high_index;
            }
        }

        return jumps;
    }
