def bsearch_interval(arr: list[list[int]], target: int):
    low = 0
    high = len(arr) - 1
    closest_index = 0

    while low <= high:
        mid = (low + high) // 2

        if arr[mid] == target:
            return mid

        if abs(arr[mid][0] - target) < abs(arr[closest_index][0] - target):
            closest_index = mid
        elif abs(arr[mid][0] - target) == abs(arr[closest_index][0] - target):
            closest_index = min(closest_index, mid)

        if arr[mid][0] < target:
            low = mid + 1
        else:
            high = mid - 1

    if arr[closest_index][1] < target:
        return closest_index + 1

    return closest_index


