    lo = 0
    hi = len(arr) - 1
    mid = 0
    while lo <= hi:
        mid = lo + (hi - lo) // 2
        if abs(arr[mid][i] - target) < abs(res[i] - target):
            res = arr[mid]

        elif abs(arr[mid][i] - target) == abs(res[i] - target):
