class Solution:
    def simplifyPath(self, path: str) -> str:
        stack = deque()

        for ch in path.split('/'):
            match ch:
                case ''| '.':
                    continue
                case '..':
                    if stack:
                        stack.pop()
                case _:
                    stack.append(ch)

        return "/" + "/".join(stack)

class Solution {
public:
    int minDistance(string word1, string word2) {
        if (word1.empty() || word2.empty())
            return max(word1.size(), word2.size());
        if (word1 == word2)
            return 0;

        int m = word1.size();
        int n = word2.size();
        vector<vector<int>> dp(m + 1, vector<int>(n + 1));


        for (int i = 1; i <= m; ++i)
            dp[i][0] = i;

        for (int j = 1; j <= n; ++j)
            dp[0][j] = j;

        for (int i = 1; i <= m; ++i)
            for (int j = 1; j <= n; ++j)
                if (word1[i - 1] == word2[j - 1])
                    dp[i][j] = dp[i - 1][j - 1];
                else
                    dp[i][j] = min({dp[i - 1][j - 1], dp[i - 1][j], dp[i][j - 1]}) + 1;


        return dp[m][n];
    }
};

