                check[x][y+1] = True
                if dfs(x, y + 1, check, index_word + 1):
                    return True
                check[x][y + 1] = False
            if y - 1 >= 0 and board[x][y - 1] == word[index_word] and not check[x][y - 1]:
                check[x][y-1] = True
                if dfs(x, y - 1, check, index_word + 1):
                    return True
                check[x][y - 1] = False

            return False

