# class TreeNode:
#     def __init__(self, val=0, left=None, right=None):
#         self.val = val
#         self.left = left
#         self.right = right
class Solution:
    def __init__(self):
        self.result = -0xFFFFFFF

    def maxPathSum(self, root: Optional[TreeNode]) -> int:
        self.result = max(self.dfs(root), self.result)
        return self.result

    def dfs(self, root: Optional[TreeNode]) -> int:

        if root.left is None and root.right is None:
            return root.val

        if root.left:
            left = self.dfs(root.left)
            self.result = max(self.result, left)
        else:
            left = 0

        if root.right:
            right = self.dfs(root.right)
            self.result = max(self.result, right)
        else:
            right = 0

        temp = root.val
        if right > 0:
            temp += right
        if left > 0:
            temp += left
        self.result = max(self.result, temp)

        branch = max(right, left)
        branch = max(root.val, branch + root.val)
        return branch

class Solution {
