        int n = s.size();
        for(int x = 0, y = n-1; x < y; x++, y--){
            while(x < n && !isalnum(s[x])){
                x++;
            }
            while(y > 0 && !isalnum(s[y])){
                y--;
            }
            if(x >= y)
                return true;

