class Solution {
public:
    int candy(vector<int>& ratings) {
        int n = ratings.size();

        int total = n;
        int peek, valley;


        for(int i = 1; i < n;){
            if (ratings[i-1] == ratings[i]){
                i++; continue;
            }
            peek = 0;
            while(i < n && ratings[i] > ratings[i - 1]){
                peek++;
                i++;
            }
            total += peek * (peek+1) / 2; // sum of ints from 1 to n

            if (i == n) {
                return total;
            }

            valley = 0;
            while(i < n && ratings[i] < ratings[i - 1]){
                valley++;
                i++;
            }
            total += valley * (valley+1) / 2;

            total -= min(peek,valley);

        }

        return total;
    }
};

