# class ListNode:
#     def __init__(self, val=0, next=None):
#         self.val = val
#         self.next = next
class Solution:
    def sortList(self, head: Optional[ListNode]) -> Optional[ListNode]:
        if not head:
            return None

        slow_head = head
        prev_head = head
        fast_head = head
        while fast_head:
            fast_head = fast_head.next
            if fast_head:
                fast_head = fast_head.next
                prev_head = slow_head
                slow_head = slow_head.next

        if head == prev_head:
            head.next = None
            if slow_head.next:
                slow_head = self.sortList(slow_head)

            return self.merge_link_list(slow_head, head)

        prev_head.next = None
        temp1 =  self.sortList(slow_head)
        temp2 = self.sortList(head)
        return self.merge_link_list(temp1, temp2)

    def merge_link_list(self, head1: Optional[ListNode], head2: Optional[ListNode])  -> Optional[ListNode]:
        result = ListNode()
        head = result
        while head1 and head2:
            if head1.val < head2.val:
                result.next = head1
                result = result.next
                head1 = head1.next
            else:
                result.next = head2
                result = result.next
                head2 = head2.next
        if head1:
            result.next = head1
        elif head2:
            result.next = head2

        return head.next

