            fast_head = fast_head.next
            if fast_head:
                fast_head = fast_head.next
                prev_head = slow_head
                slow_head = slow_head.next

        if head == prev_head:
            head.next = None
            if slow_head.next:
                slow_head = self.sortList(slow_head)
            elif slow_head == head:
                return head

            return self.merge_link_list(slow_head, head)

        prev_head.next = None
        temp1 =  self.sortList(slow_head)
        temp2 = self.sortList(head)
        return self.merge_link_list(temp1, temp2)

    def merge_link_list(self, head1: Optional[ListNode], head2: Optional[ListNode])  -> Optional[ListNode]:
        result = ListNode()
        head = result
        while head1 and head2:
            if head1.val < head2.val:
                result.next = head1
                result = result.next
                head1 = head1.next
            else:
                result.next = head2
                result = result.next
                head2 = head2.next
        if head1:
            result.next = head1
        elif head2:
            result.next = head2

        return head.next

class Solution:
    def maxPoints(self, points: List[List[int]]) -> int:
        map_p = defaultdict(int)
        result = 0
        for x1, y1 in points:
            y_inter = 0
            for x2, y2 in points:
                if x2 - x1 != 0:
                    m = (y2 - y1) / (x2 - x1)
                    b = y1 - m * x1

                    map_p[(m,b)] += 1
                else:
                    y_inter += 1

            if map_p:
                result = max(result, max(map_p.values()) + 1)
            result = max(result, y_inter)
            map_p = defaultdict(int)

        return result

