class Solution {
public:
    string reverseWords(string s) {
        int n = s.size();

        char prev = ' ';
        string myString(n, ' ');
        int index = n;

        for(int i = 0; i < n; i++){
            if(prev ==' ' && s[i] != ' '){
                int start = i;
                while(s[i] != ' ' && i < n){
                    i++;
                }
                string temp_str = s.substr(start, i-start);
                index -= temp_str.size();
                if(index -1 > 0){
                    temp_str = " " + temp_str;
                    index--;
                }
                myString.replace(index, temp_str.size(), temp_str);
            }
            prev = s[i];
        }

        int space_index = 0;
        while(myString[space_index] == ' ' && space_index < n){
            space_index++;
        }

        return myString.substr(space_index, n- space_index);
    }
};

class Solution:
    def findMin(self, nums: List[int]) -> int:
        left = 0
        right = len(nums) - 1
        test = len(nums) - 1

        while left <= right:
            mid = (left + right) // 2

            if mid + 1 >= len(nums):
                return nums[mid + 1]
            elif nums[mid] > nums[mid + 1]:
                return nums[mid + 1]
            elif nums[mid] > nums[test]:
                left = mid + 1
            else:
                right = mid - 1

        return nums[0]

