class Solution:
    def trailingZeroes(self, n: int) -> int:
        twos = 0
        fives = 0
        result = 0
        add = 1
        for i in range(1, n + 1):
            add *= i
            while add % 10 == 0:
                add //= 10
                result += 1
            if add % 2 == 0:
                twos += 1
                add //= 2
            elif add % 5 == 0:
                fives += 1
                add //= 5

        return min(twos, fives) + result

