class Solution:
    def numIslands(self, grid: List[List[str]]) -> int:
        stack = deque()
        number = 0
        for x in range(len(grid)):
            for y in range(len(grid[0])):
                if grid[x][y] == "0":
                    continue

                number += 1
                grid[x][y] = "0"
                stack.append((x,y))
                while stack:
                    j, k = stack.pop()
                    if j > 0 and grid[j - 1][k] == "1":
                        stack.append((j - 1, k))
                        grid[j - 1][k] = "0"

                    if j < len(grid) -1 and grid[j + 1][k] == "1":
                        stack.append((j + 1, k))
                        grid[j + 1][k] = "0"

                    if k > 0 and grid[j][k - 1] == "1":
                        stack.append((j, k - 1))
                        grid[j][k - 1] = "0"

                    if k < len(grid[0]) -1 and grid[j][k + 1] == "1":
                        stack.append((j, k + 1))
                        grid[j][k + 1] = "0"

        return number

