class Solution:
    def isHappy(self, n: int) -> bool:
        check = set()
        sub = ord('0')
        while n not in check:
            check.add(n)
            temp = 0
            for ch in str(n):
                temp += (ord(ch) - sub) ** 2

            if temp == 1:
                return True

            n = temp

        return False

