#         self.val = val
#         self.left = left
#         self.right = right
class Solution(object):
    def countNodes(self, root):
        if not root:
            return 0

        left = root
        right= root

        height = 0

        while right:
            if left:
                left = left.left

            right = right.right
            height += 1

        if left is None:
            return (1<<height) -1
        return 1 + self.countNodes(root.left) + self.countNodes(root.right)

class Solution:
    def summaryRanges(self, nums: List[int]) -> List[str]:
        if not nums:
            return []

        result = []
        bottom = nums[0]
        next_val = nums[0]

        for i in range(1, len(nums)):
            val = nums[i]

            if next_val + 1 == val:
                next_val = val
            else:
                if next_val == bottom:
                    result.append(str(bottom))
                else:
                    result.append(f"{bottom}->{next_val}")

                next_val = val
                bottom = val

        if next_val == bottom:
            result.append(str(bottom))
        else:
            result.append(f"{bottom}->{next_val}")

        return result

/**
 * Definition for a binary tree node.
 * struct TreeNode {
 *     int val;
 *     TreeNode *left;
 *     TreeNode *right;
 *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}
 * };
 */
class Solution {
public:
    TreeNode* lowestCommonAncestor(TreeNode* root, TreeNode* p, TreeNode* q) {
        bool pb = false;
        bool qb = false;
        return traversal(root, p->val, q->val, pb, qb);
    }
private:
    TreeNode* traversal(TreeNode* root, int p, int q, bool& pb, bool& qb){
        if (!root) return nullptr;

        bool leftPb = false, leftQb = false;
        TreeNode* left = traversal(root->left, p, q, leftPb, leftQb);

        bool rightPb = false, rightQb = false;
        TreeNode* right = traversal(root->right, p, q, rightPb, rightQb);

        pb = (leftPb || rightPb || root->val == p);
        qb = (leftQb || rightQb || root->val == q);

        if (root->val == p || root->val == q)
        return root;

        if (left && right) return root;

        return left ? left : right;
    }
};

