class Solution:
    def isAnagram(self, s: str, t: str) -> bool:
        validate = defaultdict(int)
        for ch in t:
            validate[ch] += 1

        for ch in s:
            validate[ch] -= 1

        return not any(value != 0 for value in validate.values())

