class Solution {
public:
    int hIndex(vector<int>& citations) {
        std::sort(citations.begin(), citations.end());
        int n = citations.size();

        int minn = 0;

        for(int i = 0, x = n-1; x >= 0; i++, x--){
            minn = min(citations[x], i+1);
            if(citations[x] <= i){
                return max({citations[x], i, minn});
            }
        }

        return minn;

    }
};

class Solution {
    public:
        int calc_str(string expr){
            int i = 1;
            int total = expr[0] - '0';
            int temp = 0;
            while(i < expr.size()){
                int val = expr[i+1] - '0';
                switch(expr[i]){
                    case '+':{
                        total += temp;
                        temp = val;
                        break;
                    }
                    case '-':{
                        total += temp;
                        temp = -val;
                        break;
                    }
                    case '*':{
                        if (temp == 0){ 
                            if (total == 0)
                                total = val;
                            else
                                total *= val;
                        }
                        else
                            temp *= val;
                    }
                }
                i += 2;
            }
            return total + temp;

        }


        vector<string> addOperators(string num, int target) {
            int n = num.size();
            stack<pair<string,int>> op;
            op.push(pair<string,int>{{num[0]},1});

            vector<string> result;

            while(!op.empty()){
                pair<string,int> prev_val = op.top();
                int i = prev_val.second;
                string prev_str = prev_val.first;
                op.pop();
                if(i >= num.size()){
                    if(calc_str(prev_str) == target){
                        result.push_back(prev_str);
                    }
                    continue;
                }


                op.push(pair<string,int>{{prev_str + "+" + num[i]},{i +1}});
                op.push(pair<string,int>{{prev_str + "-" + num[i]},{i +1}});
                op.push(pair<string,int>{{prev_str + "*" + num[i]},{i +1}});

            }

            return result;
        }
    };

class Solution {
    public:
        int calc_str(string expr, vector<int> &nums){
            int x = 1;
            int i = 0;
            int total = nums[0];
            int temp = 0;
            bool temp_assigned = false;
            while(i < expr.size()){
                int val = nums[x];
                switch(expr[i]){
                    case '+':{
                        if(temp_assigned)
                            total += temp;
                        temp = val;
                        temp_assigned = true;
                        break;
                    }
                    case '-':{
                        if(temp_assigned)
                            total += temp;
                        temp = -val;
                        temp_assigned = true;
                        break;
                    }
                    case '*':{
                        if (!temp_assigned){ 
                            total *= val;
                        }
                        else
                            temp *= val;
                    }
                }
                i++;
                x++;
            }
            return total + temp;

        }
        string op_str(string expr, vector<int> &nums){
            string result {};
            for(int i = 0, x = 0; i < expr.size(); i++, x +=2){
                result += to_string(nums[i]);
                result.push_back(expr[i]);
            }
            result += to_string(nums[nums.size()-1]);
            return result;

        }

        void dfs(vector<int> nums, string cmd, int i, vector<string>& result, string& num, int target){
            nums.push_back(num[i] - '0');

            if(i >= num.size()-1){
                    if(calc_str(cmd, nums) == target){
                        result.push_back(op_str(cmd, nums));
                    }
                    return;
                }
            i++;

            dfs(nums, cmd + "+", i, result, num, target);
            dfs(nums, cmd + "-", i, result, num, target);
            dfs(nums, cmd + "*", i, result, num, target);

            if(num[i-1] - '0' == 0 && nums.size() >= 2){
                nums.pop_back();
                nums[nums.size()-1] *= 10;
                dfs(nums, cmd, i, result, num, target);
            }

        }


        vector<string> addOperators(string num, int target) {
            int n = num.size();
            vector<string> result {};

            dfs({}, {}, 0, result, num, target);

            return result;
        }

    };

