class Solution:
    def gameOfLife(self, board: List[List[int]]) -> None:
        """
        Do not return anything, modify board in-place instead.
        """

        for x in range(len(board)):
            for y in range(len(board[0])):
                if board[x][y] % 2 == 1:
                    lx = x -1 >= 0
                    hx = x + 1 < len(board)
                    ly = y -1 >= 0
                    hy = y + 1 < len(board[0])
                    if lx:
                        board[x-1][y] += 2
                        if ly:
                            board[x-1][y-1] += 2
                        if hy:
                            board[x-1][y+1] += 2
                    if hx:
                        board[x+1][y] += 2
                        if ly:
                            board[x+1][y-1] += 2
                        if hy:
                            board[x+1][y+1] += 2
                    if ly:
                        board[x][y-1] += 2
                    if hy:
                        board[x][y+1] += 2

        for x in range(len(board)):
            for y in range(len(board[0])):
                board[x][y] = int(5 <= board[x][y] <= 7)

class Solution:
    def wordPattern(self, pattern: str, s: str) -> bool:
        words = defaultdict(int)
        for word in s.split():
            words[word] += 1

        patset = defaultdict(int)
        for ch in pattern:
            patset[ch] += 1

        validate = defaultdict(int)
        for nums in words.values():
