class Solution {
public:
    int eraseOverlapIntervals(vector<vector<int>>& intervals) {
        int solution = 1;
        int n = intervals.size();
        sort(intervals.begin(), intervals.end(), cmp);
        int prev = 0;
        for (int i = 1; i < n; i++){
            if(intervals[i][0] >= intervals[prev][1]){
                prev = i;
                solution++;
            }

        }

        return n - solution;
    }
private:
    static bool cmp(vector<int>& a, vector<int>& b){
        if(a[0] == b[0])
        return a[1] < b[1];
        return a[0] < b[0];
    }
