        float ave = 0;
        float greatest = 0;
        float temp = 0;
        for(int i = 0; i < nums.size(); i++){
            ave += nums[i];
        }
        if (nums.size() == 1){
            return nums[0];
        }
        for(int i = 0; i < nums.size() - k; i++){
            for(int x = i; x < (i + k); x++){
