        result: int = nums[0]
        current: int = 0

        min_result: int = nums[0]
        min_current: int = 0

        sum = 0

        for num in nums:
            sum += num

            min_current += num
            min_result = min(min_result, min_current)
            if min_current > 0:
                min_current = 0


            current += num
            result = max(result, current)
            if current < 0:
                current = 0

        if sum != min_result:
            result = max(result, sum -min_result)
        return result

