    int tribonacci(int n) {
        if(!n)
        return 0;
        if(n == 1 || n == 2)
        return 1;
        queue<int> tri;
        tri.push(0); tri.push(1); tri.push(1);
        int mid = 1;
        int temp;
        for (int i = 2; i < n; i++){
            temp = tri.front() + mid + tri.back();
            mid = tri.back();
