            tri.push(temp);
        }
        return temp;
    }
};

class Solution {
public:
    int longestCommonSubsequence(string text1, string text2) {
        int n = text1.size();
        int m = text2.size();
        vector<vector<int>> DP( n + 1, vector<int>(m+1, -1));

        for(int i = 0; i <= n; i++) DP[i][0] = 0;
        for(int i = 0; i <= m; i++) DP[0][i] = 0;

        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= m; j++) {
                if (text1[i - 1] == text2[j - 1]) {
                    DP[i][j] = DP[i - 1][j - 1] + 1;
                } else {
                    DP[i][j] = max(DP[i - 1][j], DP[i][j - 1]);
                }
            }
        }

        return DP[n][m];
        }
};

