    int maxVowels(string s, int k) {
        int pts = 0;
        for(int i = 0; i < k; i++){
            if(test(s[i]))
                pts++;
        }

        int max = pts;
        for(int i = k; i < s.size(); i++){
            if(test(s[i -k]))
                pts--;
