class Solution {
public:
    int nearestExit(vector<vector<char>>& maze, vector<int>& entrance) {
        int y = entrance[0];
        int x = entrance[1];
        int lowestt = 99999;
        int ymax = maze.size();
        int xmax = maze[0].size(); 
        set<pair<int, int>> travel;
        travel.insert(make_pair(y, x));
        stack<tuple <int, int, int>> g;
        g.push(make_tuple(y,x,0));

        while (!g.empty()) {
        bfs(maze, get<1>(g.top()), get<0>(g.top()), lowestt, xmax, ymax, get<2>(g.top()), travel, g);
        g.pop();
        } 
        return (lowestt == 0) ? -1 : lowestt;
    }

private:
    void bfs(vector<vector<char>>& maze, int x, int y, int& lowestt, int xmax, int ymax, int turns, set<pair<int, int>>& travel, stack<tuple <int, int, int>>& g) {
        if (!travel.contains(make_pair(y, x)) && (x == 0 || x == xmax - 1 || y == 0 || y == ymax - 1)) {
            travel.insert(make_pair(y, x));
            lowestt = min(lowestt, turns);
        } else {
            travel.insert(make_pair(y, x));
            if (x != xmax - 1 && !travel.contains(make_pair(y, x + 1)) && maze[y][x + 1] == '.') 
            g.push(make_tuple(x+1,y, turns+1));

            if (x != 0 && !travel.contains(make_pair(y, x - 1)) && maze[y][x - 1] == '.') 
            g.push(make_tuple(x-1,y, turns+1));

            if (y != ymax - 1 && !travel.contains(make_pair(y + 1, x)) && maze[y + 1][x] == '.') 
            g.push(make_tuple(x,y+1, turns+1));

            if (y != 0 && !travel.contains(make_pair(y - 1, x)) && maze[y - 1][x] == '.') 
            g.push(make_tuple(x,y-1, turns+1));
        }
    }
};

class Solution {
public:
    int nearestExit(vector<vector<char>>& grid, vector<int>& entrance) {

        int n = grid.size();

        int m = grid[0].size();

        // direction co-ordinates

        vector<int> dx = {-1, 0, 1, 0};

        vector<int> dy = {0, 1, 0, -1};

        // declare a queue

        queue<pair<int, int>> q;

        // push the entracnce point into queue

        q.push({entrance[0], entrance[1]});

        int level = 0;

        // mark the entrance cell as visited

        grid[entrance[0]][entrance[1]] = '+';

        while(!q.empty())
        {
            int size = q.size();

            while(size--)
            {
                auto curr = q.front();

                q.pop();

                int i = curr.first;

                int j = curr.second;

                // if exit cell is found return level

                if(!(i == entrance[0] && j == entrance[1]) && (i == 0 || j == 0 || i == n - 1 || j == m - 1))
                {
                    return level;
                }

                // push the next level cell into queue which is not visited and don't have wall and mark that cell as visited

                for(int k = 0; k < 4; k++)
                {
                    int new_i = i + dx[k];

                    int new_j = j + dy[k];

                    if(new_i >= 0 && new_i < n && new_j >= 0 && new_j < m && grid[new_i][new_j] != '+')
                    {
                        grid[new_i][new_j] = '+';

                        q.push({new_i, new_j});
                    }
                }
            }

            // increment level

            level++;
        }

        return -1;
    }
};

/**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode() : val(0), next(nullptr) {}
 *     ListNode(int x) : val(x), next(nullptr) {}
 *     ListNode(int x, ListNode *next) : val(x), next(next) {}
 * };
 */
class Solution {
public:
    ListNode* deleteMiddle(ListNode* head) {
        if (!head || !head->next) {
            return nullptr;
        }
        ListNode* temp = head;
        ListNode* doubletemp = head;
        ListNode* prev = nullptr;
        int index = 0;
        while(doubletemp && doubletemp->next){
            doubletemp = doubletemp->next->next;
            prev = temp;
            temp = temp->next;
        }
        if(prev){
            prev->next = temp->next;
        }
        delete temp;
        return head;
    }
};

/**
 * Definition for singly-linked list.
 * struct ListNode {
 *     int val;
 *     ListNode *next;
 *     ListNode() : val(0), next(nullptr) {}
 *     ListNode(int x) : val(x), next(nullptr) {}
 *     ListNode(int x, ListNode *next) : val(x), next(next) {}
 * };
 */
class Solution {
public:
    int pairSum(ListNode* head) {
        ListNode* doub = head;
        ListNode* temp = head;
        stack<int> stack;
        int greatest = 0;
        while(doub && doub->next){
            doub = doub->next->next;
            stack.push(temp->val);
            temp = temp->next;
        }
        while(temp){
            if(temp->val + stack.top() > greatest)
            greatest = temp->val + stack.top();

            temp = temp->next;
            stack.pop();
        }
        return greatest;
    }
};

class Solution {
public:
    vector<int> successfulPairs(vector<int>& spells, vector<int>& potions, long long success) {
    sort(potions.begin(),potions.end());
    int m = potions.size();
    int maxPotionValue=potions[m-1];

    vector<int> solution; 
    long long value;
    for (auto temp : spells){
        value = ceil(1.0 * success / temp);
        if(value>maxPotionValue){
                solution.push_back(0);
                continue;
            }
        int index=lower_bound(potions.begin(),potions.end(),value)-potions.begin();
        int count=m-index;
        solution.push_back(count);

    }
    return solution;
    }
};

