class Solution {
public:
    int equalPairs(vector<vector<int>>& grid) {
        int size = grid.size();
        std::map<std::vector<int>, int> pair;
        int count = 0;

        for (auto row : grid) {
            pair[row]++;
        }

        std::vector<int> myvector(size); 
        for (int x = 0; x < size; x++) {
            for (int y = 0; y < size; y++) {
                myvector[y] = grid[y][x];
            }
            if (pair.find(myvector) != pair.end()) {
                count += pair[myvector];
            }
        }

        return count;
    }
};

class Solution {
public:
    string removeStars(string s) {
        int rem = 0;
        for(int i = s.size() - 1; i >= 0; i--){
            if(s[i] == '*'){
                rem++;
            } else if (rem > 0) {
                rem--;
            } else {
                continue;
            }
            s.erase(i, 1); 
        }
        return s;
    }
};

class Solution {
public:
    long long totalCost(vector<int>& costs, int k, int candidates) {
    int n = costs.size();
    priority_queue <int, vector<int>, greater<int>> temp1;
    priority_queue <int, vector<int>, greater<int>> temp2;
    for (int i=0;i<candidates;i++){
        temp1.push(costs[i]);
        }
    for (int i=n-1;i>=n-candidates && i >= candidates ;i--){
        temp2.push(costs[i]);
    }
    int cursor1 =candidates;
    int cursor2 = n-candidates-1;
    long long cost = 0;
    while(k--){
    int a  = INT_MAX;
    int b  = INT_MAX;
    if(!temp1.empty())
    a = temp1.top();
    if(!temp2.empty())
    b = temp2.top();

    if(a<=b){
        cost += a;
        temp1.pop();
        if(cursor1<=cursor2){
            temp1.push(costs[cursor1]);
            cursor1++;
        }
        }
    else{
        cost += b;
        temp2.pop();
        if(cursor1<=cursor2){
            temp2.push(costs[cursor2]);
            cursor2--;
        }
    }


    }
    return cost;
    }
};

class Solution {
public:
    long long maxScore(vector<int>& nums1, vector<int>& nums2, int k) {
        vector<pair<int,int>>v;
        int n=nums2.size();
        for(int i=0;i<n;i++){
            v.push_back({nums2[i],i});
        }
        sort(v.rbegin(),v.rend());
        priority_queue <int, vector<int>, greater<int>> gq;

        long long maxsum = 0;
        long long sum = 0;
        for(int i = 0; i < v.size(); i++){
            auto &[a,b]=v[i];
            sum += nums1[b];
            gq.push(nums1[b]);
            if(k==gq.size()){
                maxsum = max(maxsum, sum * a);
            }
            if(k - 1 < gq.size()){
                sum -= nums1[b];
                gq.pop();
            }
        }
        return maxsum;

    }
};

